const input = $input.first().json.body;

if (!input.contract_id) {
  throw new Error("Missing required field: contract_id");
}

if (!input.user_id) {
  throw new Error("Missing required field: user_id");
}

if (!input.compliance) {
  throw new Error("Missing required field: compliance (compliance data object)");
}

const validated = {
  contract_id: input.contract_id,
  user_id: input.user_id,
  format: input.format || "both",
  regenerate: input.regenerate || false,
  document_type: "playbook-compliance",
  source_type: "quick_contract",
  requested_at: new Date().toISOString(),

  // Compliance data passed from frontend
  compliance: input.compliance,
  playbook_name: input.playbook_name || "Playbook",
  company_name: input.company_name || "Company",
};

return [{ json: validated }];

const request = $("Validate Request").first().json;
const postgresResult = $input.all();

let cachedDocument = null;
let hasCached = false;

if (postgresResult && postgresResult.length > 0) {
  const firstResult = postgresResult[0].json;
  if (firstResult && firstResult.document_id) {
    cachedDocument = firstResult;
    hasCached = true;
  }
}

let action = "generate_new";
if (hasCached && !request.regenerate) {
  action = "return_cached";
}

const output = {
  contract_id: request.contract_id,
  user_id: request.user_id,
  format: request.format,
  regenerate: request.regenerate,
  document_type: request.document_type,
  source_type: request.source_type,
  requested_at: request.requested_at,
  compliance: request.compliance,
  playbook_name: request.playbook_name,
  company_name: request.company_name,
  has_cached: hasCached,
  cached_document: cachedDocument,
  action: action,
};

return [{ json: output }];

const cached = $("Check Existing Document").first().json;

return [
  {
    json: {
      success: true,
      cached: true,
      document_id: cached.document_id,
      document_type: "playbook-compliance",
      source_type: "quick_contract",
      status: cached.status,
      downloads: {
        pdf: cached.storage_path_pdf
          ? `/api/documents/download/${cached.document_id}?format=pdf`
          : null,
        docx: null,
      },
      preview: cached.preview_data,
      generated_at: cached.created_at,
    },
  },
];

const contractData = $("Fetch Contract Details").first().json;
const recipientData = $("Fetch Recipient Details").first().json;
const request = $("Validate Request").first().json;
const compliance = request.compliance;

// Date formatting
const now = new Date();
const generatedDate = now.toLocaleDateString("en-GB", {
  day: "numeric",
  month: "long",
  year: "numeric",
});
const generatedTime = now.toLocaleTimeString("en-GB", {
  hour: "2-digit",
  minute: "2-digit",
});

// Score colour logic
const score = compliance.overallScore || 0;
let scoreColour = "#10b981"; // emerald
if (score < 50) scoreColour = "#ef4444"; // red
else if (score < 75) scoreColour = "#f59e0b"; // amber

const hasBreaches = (compliance.redLineBreaches || 0) > 0;

// Build red lines array for template
const redLines = (compliance.redLines || []).map((rl) => ({
  rule: rl.rule || rl.name || "Rule",
  status: rl.breached ? "BREACH" : "PASS",
  statusColour: rl.breached ? "#ef4444" : "#10b981",
  detail: rl.detail || rl.assessment || "",
  clause: rl.clauseName || rl.clause || "",
}));

// Build categories array for template
const categories = (compliance.categories || []).map((cat) => ({
  name: cat.name || cat.category || "Category",
  score: cat.score != null ? cat.score : "-",
  status: cat.status || (cat.score >= 80 ? "Good" : cat.score >= 50 ? "Warning" : "Fail"),
  statusColour: cat.score >= 80 ? "#10b981" : cat.score >= 50 ? "#f59e0b" : "#ef4444",
  ruleCount: cat.ruleCount || cat.rules || 0,
  detail: cat.detail || cat.assessment || "",
}));

// Build flexibility array for template
const flexibility = (compliance.flexibility || []).map((flex) => ({
  clause: flex.clauseName || flex.clause || "Clause",
  category: flex.category || "General",
  currentPosition: flex.currentPosition || flex.position || "-",
  playbookMin: flex.playbookMin || flex.min || "-",
  playbookMax: flex.playbookMax || flex.max || "-",
  withinRange: flex.withinRange != null ? flex.withinRange : true,
  statusColour: flex.withinRange !== false ? "#10b981" : "#ef4444",
  statusLabel: flex.withinRange !== false ? "Within range" : "Outside range",
}));

const templateData = {
  // Header
  reportTitle: "Playbook Compliance Report",
  contractName: contractData.file_name || contractData.contract_name || "Contract",
  contractType: contractData.detected_contract_type || contractData.contract_type_key || "Contract",
  generatedDate: generatedDate,
  generatedTime: generatedTime,

  // Parties
  initiatorCompany: contractData.initiator_company || request.company_name || "Initiator",
  initiatorName: `${contractData.initiator_first_name || ""} ${contractData.initiator_last_name || ""}`.trim() || "Unknown",
  respondentCompany: recipientData.recipient_company || "Respondent",
  respondentName: recipientData.recipient_name || "Unknown",

  // Playbook
  playbookName: request.playbook_name,
  companyName: request.company_name,

  // Overall score
  overallScore: score,
  scoreColour: scoreColour,
  scoreLabel: score >= 80 ? "Compliant" : score >= 50 ? "Partially Compliant" : "Non-Compliant",

  // Rule summary
  rulesPassed: compliance.rulesPassed || 0,
  rulesWarning: compliance.rulesWarning || 0,
  rulesFailed: compliance.rulesFailed || 0,
  totalRules: (compliance.rulesPassed || 0) + (compliance.rulesWarning || 0) + (compliance.rulesFailed || 0),

  // Red lines
  hasBreaches: hasBreaches,
  redLineBreaches: compliance.redLineBreaches || 0,
  redLineTotal: redLines.length,
  redLines: redLines,

  // Categories
  categories: categories,

  // Flexibility
  flexibility: flexibility,

  // Footer
  footer: {
    clarence_version: "1.0",
    document_id: request.contract_id,
    confidentiality: "CONFIDENTIAL - Initiator eyes only. This report is not shared with the counterparty.",
  },
};

return [
  {
    json: {
      template_data: templateData,
      preview_data: {
        title: `Playbook Compliance: ${templateData.initiatorCompany} — ${request.playbook_name}`,
        generated_at: request.requested_at,
        sections: ["Overall Score", "Red Lines", "Categories", "Flexibility"],
        summary: {
          score: score,
          redLineBreaches: compliance.redLineBreaches || 0,
          rulesPassed: compliance.rulesPassed || 0,
          rulesFailed: compliance.rulesFailed || 0,
          playbookName: request.playbook_name,
        },
      },
    },
  },
];

const request = $("Validate Request").first().json;
const templateData = $("Prepare API Template").first().json;

const supabaseProject = "wlrlkvqiakaiydfqqdmu";
const bucket = "documents";
const filename = `${request.contract_id}_qc_playbook_compliance.pdf`;
const storagePath = `playbook-compliance/${filename}`;

const publicUrl = `https://${supabaseProject}.supabase.co/storage/v1/object/public/${bucket}/${storagePath}`;

return [
  {
    json: {
      ...templateData,
      pdf_generated: true,
      storage_path_pdf: storagePath,
      pdf_public_url: publicUrl,
      pdf_bucket: bucket,
      pdf_filename: filename,
    },
  },
];

const savedDoc = $("Save Document Record").first().json;
const storageData = $("Process Storage Response").first().json;
const request = $("Validate Request").first().json;

const response = {
  success: true,
  cached: false,
  document_id: savedDoc.document_id,
  document_type: "playbook-compliance",
  source_type: "quick_contract",
  status: "generated",
  downloads: {
    pdf: storageData.pdf_public_url || null,
    docx: null,
  },
  pdf_public_url: storageData.pdf_public_url || null,
  preview: storageData.preview_data,
  generated_at: savedDoc.created_at,
  metadata: {
    contract_id: request.contract_id,
    storage_path: storageData.storage_path_pdf,
    bucket: storageData.pdf_bucket,
  },
};

return [{ json: response }];
